pr_description:
### Summary
Prevent adding duplicate plugins

### Bug description
After upgrading an old config I got this error:

```sh
Module build failed: Error: Duplicate plugin/preset detected.
```

#### Old config
```json
{
  "presets": [
    ["env", {
      "useBuiltIns": "usage",
      "targets": {
        "browsers": ["> 0.25%"]
      },
      "modules": false,
      "loose": true
    }],
    "stage-1",
    "react",
    "flow"
  ],

  "plugins": [
    "transform-decorators-legacy",
    "transform-react-display-name",
    "transform-class-properties",
    ["import", { "libraryName": "antd", "style": "css" }]
  ],

  "env": {
    "production": {
      "plugins": ["transform-react-remove-prop-types"]
    },
    "development": {
      "plugins": [
        "react-hot-loader/babel"
      ]
    },
    "test": {
      "presets": [
        ["env", {
          "useBuiltIns": "usage",
          "targets": {
            "browsers": ["> 0.25%"]
          },
          "modules": false,
          "loose": true
        }],
        "react"
      ],
      "plugins": [
        "transform-runtime",
        "transform-decorators-legacy",
        "transform-react-display-name",
        "transform-class-properties",
        ["import", { "libraryName": "antd", "style": "css" }]
      ]
    }
  }
}

```

#### After upgrade

```json
{
  "presets": [
    [
      "@babel/preset-env",
      {
        "useBuiltIns": "usage",
        "targets": {
          "browsers": [
            "> 0.25%"
          ]
        },
        "modules": false,
        "loose": true
      }
    ],
    "@babel/preset-react",
    "@babel/preset-flow"
  ],
  "plugins": [
    [
      "@babel/plugin-proposal-decorators",
      {
        "legacy": true
      }
    ],
    "@babel/plugin-transform-react-display-name",
    "@babel/plugin-proposal-class-properties",
    [
      "import",
      {
        "libraryName": "antd",
        "style": "css"
      }
    ],
    "@babel/plugin-syntax-dynamic-import",
    "@babel/plugin-syntax-import-meta",
    "@babel/plugin-proposal-class-properties",
    "@babel/plugin-proposal-json-strings",
    [
      "@babel/plugin-proposal-decorators",
      {
        "legacy": true
      }
    ],
    "@babel/plugin-proposal-function-sent",
    "@babel/plugin-proposal-export-namespace-from",
    "@babel/plugin-proposal-numeric-separator",
    "@babel/plugin-proposal-throw-expressions",
    "@babel/plugin-proposal-export-default-from",
    "@babel/plugin-proposal-logical-assignment-operators",
    "@babel/plugin-proposal-optional-chaining",
    [
      "@babel/plugin-proposal-pipeline-operator",
      {
        "proposal": "minimal"
      }
    ],
    "@babel/plugin-proposal-nullish-coalescing-operator",
    "@babel/plugin-proposal-do-expressions"
  ],
  "env": {
    "production": {
      "plugins": [
        "transform-react-remove-prop-types"
      ]
    },
    "development": {
      "plugins": [
        "react-hot-loader/babel"
      ]
    },
    "test": {
      "presets": [
        [
          "@babel/preset-env",
          {
            "useBuiltIns": "usage",
            "targets": {
              "browsers": [
                "> 0.25%"
              ]
            },
            "modules": false,
            "loose": true
          }
        ],
        "@babel/preset-react"
      ],
      "plugins": [
        "@babel/plugin-transform-runtime",
        [
          "@babel/plugin-proposal-decorators",
          {
            "legacy": true
          }
        ],
        "@babel/plugin-transform-react-display-name",
        "@babel/plugin-proposal-class-properties",
        [
          "import",
          {
            "libraryName": "antd",
            "style": "css"
          }
        ]
      ]
    }
  }
}

```

#### Duplicates

```

[
  "@babel/plugin-proposal-decorators",
  {
    "legacy": true
  }
],
"@babel/plugin-proposal-class-properties",

```

### Solution
This code uses a `Set` to keep track of existing plugin names and prevents adding dupes. Duplicates are discarded.

